import { useState } from 'react';
import { create } from '../services/api';

export default function Apply() {
  const [form, setForm] = useState({
  name: '',
  dob: '',
  address: '',
  documents_submitted: 0,
  police_verification: 'Pending',
});
  const [msg, setMsg]       = useState(null); // { type: 'success'|'error', text }
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.applicant_id.trim()) {
      setMsg({ type: 'error', text: 'Please enter a valid Applicant ID.' });
      return;
    }
    setLoading(true);
    try {
      await create(form);
      setMsg({ type: 'success', text: 'Application submitted successfully!' });
      setForm({ applicant_id: '', documents_submitted: 0, police_verification: 'Pending' });
    } catch {
      setMsg({ type: 'error', text: 'Submission failed. Please try again.' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page">
      <div className="container-sm">
        <div className="page-header">
          <h2>Apply for Passport</h2>
          <div className="divider" />
          <p>Fill in the details below to submit a new application.</p>
        </div>

        <div className="card">
          {msg && (
            <div className={`alert alert-${msg.type}`}>
              {msg.type === 'success' ? '✅' : '⚠️'} {msg.text}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Applicant ID</label>
              <input
                placeholder="e.g. 1042"
                value={form.applicant_id}
                onChange={e => setForm({ ...form, applicant_id: e.target.value })}
              />
            </div>

            <div className="form-group">
              <label>Documents Submitted</label>
              <select
                value={form.documents_submitted}
                onChange={e => setForm({ ...form, documents_submitted: e.target.value })}
              >
                <option value={0}>No — Not yet submitted</option>
                <option value={1}>Yes — All documents in</option>
              </select>
            </div>

            <div className="form-group">
              <label>Police Verification</label>
              <select
                value={form.police_verification}
                onChange={e => setForm({ ...form, police_verification: e.target.value })}
              >
                <option value="Pending">Pending</option>
                <option value="Approved">Approved</option>
                <option value="Rejected">Rejected</option>
              </select>
            </div>

            <button type="submit" className="btn btn-primary btn-full" disabled={loading}>
              {loading ? 'Submitting…' : 'Submit Application →'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
